import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup } from '@angular/forms';
import { HttpClient } from '@angular/common/http';
import { Router } from '@angular/router';

@Component({
  selector: 'app-search-page',
  templateUrl: './search-page.component.html',
  styleUrls: ['./search-page.component.css']
})
export class SearchPageComponent implements OnInit {
  searchForm: FormGroup;
  provinces: any[] = []; // Danh sách tỉnh/thành phố
  jobsList: any[] = []; // Danh sách ngành nghề
  selectedProvince: any = null;
  selectedJob: any = null;
  filterSalary: boolean = false;
  minSalary: number | null = null;
  maxSalary: number | null = null;
  filterJobDefault: boolean = false;
  filterWorkingType: boolean = false;
  workingType: number | null = null;
  filterExperience: boolean = false;
  requiredExperienceLevel: number | null = null;
  searchResults: any[] = [];
  isLoading: boolean = false;
  totalCount: number = 0;
  totalPage: number = 1;
  page: number = 1;
  pageSize: number = 10;

  constructor(
    private fb: FormBuilder,
    private http: HttpClient,
    private router: Router
  ) {
    this.searchForm = this.fb.group({
      searchKey: ['']
    });
  }

  ngOnInit(): void {
    // Tải danh sách tỉnh/thành phố và ngành nghề (giả lập hoặc gọi API)
    this.loadProvinces();
    this.loadJobsList();
  }

  loadProvinces(): void {
    // Gọi API hoặc mock dữ liệu tỉnh/thành phố
    this.provinces = [
      { id: 1, name: 'Đà Nẵng' },
      { id: 2, name: 'Hà Nội' },
      { id: 3, name: 'TP. Hồ Chí Minh' }
      // Thêm các tỉnh/thành phố khác
    ];
  }

  loadJobsList(): void {
    // Gọi API hoặc mock dữ liệu ngành nghề
    this.jobsList = [
      { id: 97, name: 'Nhân viên Telesales' },
      { id: 98, name: 'Lập trình viên' }
      // Thêm các ngành nghề khác
    ];
  }

  onProvinceSelected(event: any): void {
    this.selectedProvince = event;
  }

  onSelectJob(event: any): void {
    this.selectedJob = event;
  }

  onSearch(): void {
    this.page = 1; // Reset về trang 1 khi tìm kiếm mới
    this.performSearch();
  }

  changePage(newPage: number): void {
    if (newPage >= 1 && newPage <= this.totalPage) {
      this.page = newPage;
      this.performSearch();
    }
  }

  performSearch(): void {
    this.isLoading = true;
    const searchCondition = {
      searchKey: this.searchForm.get('searchKey')?.value || null,
      minSalary: this.filterSalary && this.minSalary ? this.minSalary * 1000000 : null,
      maxSalary: this.filterSalary && this.maxSalary ? this.maxSalary * 1000000 : null,
      jobDefaultId: this.filterJobDefault && this.selectedJob ? this.selectedJob.id : null,
      workingType: this.filterWorkingType ? this.workingType : null,
      requiredExperienceLevel: this.filterExperience ? this.requiredExperienceLevel : null,
      province: this.selectedProvince ? this.selectedProvince.name : null,
      page: this.page,
      size: this.pageSize
    };

    this.http.post('http://localhost:2000/bs-user/bs-job/_search_advanced', searchCondition)
      .subscribe({
        next: (response: any) => {
          this.searchResults = response.data || [];
          this.totalCount = response.totalCount || 0;
          this.totalPage = response.totalPage || 1;
          this.isLoading = false;
        },
        error: (error) => {
          console.error('Search error:', error);
          this.searchResults = [];
          this.isLoading = false;
        }
      });
  }

  onViewDetailItem(job: any): void {
    // Chuyển hướng đến trang chi tiết công việc
    this.router.navigate(['/job', job.id]);
  }
}
